	keep	obj/file	mcopy file.mac******************************************************************  FileNames - common area for file names******************************************************************FileNames datafvarSize equ	4	size of a file variablefname	ds	fvarSize	name of file to processmname	ds	fvarSize	macro file nameoname	ds	fvarSize	output file name	end******************************************************************  FileCommon - common data for the file module******************************************************************	copy	DirectPageFileCommon privdata;;  Constants;fbuffSize equ	8096	file buffer size;;  I/O records;ffDCB	dc	i'14'	fast file DCBffAction ds	2ffIndex	ds	2ffFlags	ds	2ffFileHandle ds 4ffPathName ds	4ffAccess ds	2ffFileType ds	2ffAuxType ds	4ffStorageType ds 2ffCreate ds	8ffMod	ds	8ffOption ds	4ffFileLength ds 4ffBlocksUsed ds 4ffCheckSum ds	2	end******************************************************************  CheckVersion - check the shell version**  Outputs:*	C - set if the shell is not present or is an old version******************************************************************CheckVersion start	OSVersion vrDCB	bcs	lb1	lda	vrNumber	and	#$00FF	cmp	#'2'	blt	lb1	clc	rtslb1	puts	#'Requires shell version 2.0 or greater.',cr=t,errout=t	lda	#-1	quit	qt_DCBqt_DCB	anop		quit DCB	dc	a4'qt_flags'qt_flags dc	i'0'vrDCB	dc	i'1'vrNumber ds	4	end******************************************************************  CopyFileName - copy a string to a file name buffer**  Inputs:*	fptr - ptr to file name variable*	sptr - string pointer******************************************************************CopyFileName startptr	equ	1	file name buffer pointerlen	equ	5	length of the file name	sub	(4:sptr,4:fptr),6	ldy	#2	free the old file buffer	lda	[fptr],Y	pha	lda	[fptr]	pha	jsr	Free	lda	[sptr]	get a file buffer	xba	and	#$00FF	sta	len	inc	A	inc	A	pha	jsr	Malloc	sta	ptr	sta	[fptr]	ldy	#2	txa	sta	ptr+2	sta	[fptr],Y	short M	copy the file name	ldy	len	inylb1	lda	[sptr],Y	sta	[ptr],Y	dey	bpl	lb1	long	M	lda	len	set the length	sta	[ptr]	ret	end******************************************************************  CursorOff - turn the cursor off******************************************************************CursorOff start	rts	end******************************************************************  CursorOn - turn the cursor on******************************************************************CursorOn	 start	rts	end******************************************************************  ExpandDevice - expand device stuff**  Inputs:*	fhand - ptr to the file name variable**  Returns:*	Error number; 0 if there was no error******************************************************************ExpandDevice start	using FileCommonerr	equ	1	error numberptr	equ	3	file name pointerptr2	equ	7	file name pointer	sub	(4:fhand),10	ph2	#fbuffSize+4	get an output file buffer	jsr	Malloc	sta	ptr	sta	edOut	stx	ptr+2	stx	edOut+2	lda	#fbuffSize+4	sta	[ptr]	ldy	#2	set the input file name	lda	[fhand],Y	sta	edIn+2	lda	[fhand]	sta	edIn	OSExpandDevices edRec	expand the devices	sta	err	ph4	edIn	free the old buffer	jsr	Free	add4	edOut,#2,ptr	get a pointer to the new name	lda	[ptr]	allocate space for the returned name	inc	A	inc	A	pha	jsr	Malloc	ldy	#2	sta	ptr2	sta	[fhand]	txa	sta	ptr2+2	sta	[fhand],Y	lda	[ptr]	copy the file name	tay	short M	inylb1	lda	[ptr],Y	sta	[ptr2],Y	dey	bpl	lb1	long	M	ph4	ptr	free the work buffer	jsr	Free	ret	2:erredRec	dc	i'2'edIn	ds	4edOut	ds	4	end******************************************************************  GetTabs - Get the tab line**  Inputs:*	langNum - language number to read**  Outputs:*	tabs - tab line**  Notes:*	This subroutine can be called with long or short*	registers.******************************************************************GetTabs	start	using Common	using FileCommon	move	#0,tabs,#256	initialize tab line	ldy	#7	a tab every 8 spaceslb4	lda	#1	sta	tabs,Y	tya	clc	adc	#8	tay	cpy	#255	blt	lb4	ldy	#79	set end of line marker	lda	#2	sta	tabs,Y	lla	ffPathName,systabs	load the tab file	stz	ffAction	lda	#$C000	sta	ffFlags	OSFastFile ffDCB	bcc	gt1rts	rts		ok if no tab file use defaultsgt1	move4 ffFileHandle,r4	dereference the handle	ldy	#2	lda	[r4]	sta	r0	lda	[r4],Y	sta	r2	jsr	FindLn	find the tab line	jcc	rt1	jsr	Skip	skip the editor flags;;  Get the tab line;	ldy	#0	read in the tab linegt3	phy	jsr	GetC	ply	bcs	gt4	and	#$0F	cmp	#RETURN	beq	gt4	short M	sta	tabs,Y	long	M	iny	cpy	#256	blt	gt3gt4	short M	lda	#2	sta	tabs,Y	long	Mrt1	lda	#7	purge the file	sta	ffAction	lla	ffPathName,systabs	OSFastFile ffDCB	rts;;  Locatate the correct tab line;FindLn	stz	numfn1	jsr	GetC	Get a decimal number	bcs	err	jsr	IsDigit	bcc	fn2	and	#$000F	pha	lda	num	ldx	#10	jsl	~mul2	clc	adc	1,S	plx	sta	num	bra	fn1fn2	cmp	#RETURN	make sure this is the end of line	beq	fn3err	clc	rtsfn3	lda	num	see if we found the tab line	cmp	langNum	beq	fn4	jsr	Skip	skip past settings	jsr	Skip	skip past tab line	brl	FindLn	next tabfn4	sec	rts;;  Skip to next line;Skip	jsr	GetC	bcs	srts	cmp	#RETURN	bne	Skipsrts	rts;;  GetC - get a character; return C=1 if at end of file;GetC	lda	ffFileLength	beq	sec	dec	ffFileLength	lda	[r0]	inc4	r0	and	#$00FF	clc	rtssec	sec	rtsnum	ds	2systabs	dos	'15/systabs'	end******************************************************************  InitFile - initialize the file module******************************************************************InitFile start	using FileNames	jsr	CheckVersion	lla	fname,0	lla	oname,0	lla	mname,0	rts	end******************************************************************  MacroFile - Get a macro file**  Outputs:*	fptr - points to first byte of file******************************************************************MacroFile start	using FileCommon	using FileNames	using Common;;  Branch if there is a wild card search in progress.;	lda	wcard	jne	lb6;;  Open a new file.;lb1	strlen token	skip prompt if there is input	bne	lb2         jsr	StopSpin	putcr	puts	#'Macro file name: '	jsr	GetLine	jsr	NextToken	quit if no name given	strlen token	bne	lb2erts	clc	rtslb2	stz	wcard	lda	token+1	if there is a wildcard then	and	#$00FF	  WCARD = 1	tax	short Mlb3	lda	token+1,X	cmp	#'='	beq	lb4	cmp	#'?'	beq	lb4	dbne	X,lb3	bra	lb5lb4	inc	wcardlb5	long	M	ph4	#token	set up a wildcard search	ph4	#wc_name	jsr	CopyFileName	OSInit_Wildcard wc_DCB	bcc	lb5a	jsr	ProDOSError	ph4	wc_name	jsr	Free	stz	wc_name	stz	wc_name+2	jsr	NextToken	brl	lb1lb5a	ph4	wc_name	free the init wildcard name	jsr	Free	stz	wc_name	stz	wc_name+2	jsr	Next	get first match, just to be sure there	move4 fname,r0	 are some	lda	[r0]	bne	lb5b	puts	#'File not found: ',errout=t	puts	token,cr=t,errout=t    	jsr	NextToken	next file name	brl	lb1lb5b	jsr	NextToken	next file name	bra	lb7lb6	jsr	Next	get a file	move4 fname,r0	lda	[r0]	bne	lb7	stz	wcard	jsr	Unresolved	jcc	erts	brl	lb1lb7	lda	wcard	print the processing message	beq	lb8         lda	progress	beq	lb8	puts	#'Processing '	ph4	#fname	ph2	#0	jsr	PrintFileName	putcrlb8	jsr	Open	return with the file	ph4	mname	make a copy of the file name	jsr	Free	move4 fname,r0	lda	[r0]	inc	A	inc	A	pha	jsr	Malloc	sta	mname	sta	r4	stx	mname+2	stx	r6	lda	[r0]	tay	iny	short Mlb9	lda	[r0],Y	sta	[r4],Y	dey	bpl	lb9	long	M	sec	rtserr	jsr	ProDOSError	brl	lb1;;  Next - get the next wildcard name;Next	ph2	#fbuffSize+4	get an output name buffer	jsr	Malloc	sta	r0	sta	nw_name	stx	r2	stx	nw_name+2	lda	#fBuffSize+4	sta	[r0]	OSNext_Wildcard nw_dcb	get the name	ph4	fname	free(fname)	jsr	Free	add4	r0,#2	get a new file name buffer	lda	[r0]	inc	A	inc	A	pha	jsr	Malloc	sta	fname	sta	r4	stx	fname+2	stx	r6	lda	[r0]	tay	iny	short Mnx1	lda	[r0],Y	sta	[r4],Y	dey	bpl	nx1	long	M	ph4	r0	free the output name buffer	jsr	Free	rts;;  Local data;wc_dcb	dc	i'2'	InitWildcard Recordwc_name	ds	4wc_flag	dc	i'0'nw_dcb	dc	i'1'	NextWildcard recordnw_name	ds	4	end******************************************************************  Open - Open the File**  Inputs:*	fname - name of the file to open**  Outputs:*	flen - pointer to last byte + 1 of file*	fptr - pointer to first byte of file******************************************************************Open	start	using Common	using FileNames	using FileCommon	move4 fname,ffPathname	read the file	stz	ffAction	lda	#$C000	sta	ffFlags	OSFastFile ffDCB	jcs	err2	lda	ffFiletype	check the file type	cmp	#TXT	beq	lb1	cmp	#SRC	bne	err1lb1	move4 ffFileHandle,r0	set the file pointer	ldy	#2	lda	[r0]	sta	fptr	lda	[r0],Y	sta	fptr+2	add4	fptr,ffFilelength,flen	set the EOF pointer	lda	ffFileType	get the language number	cmp	#TXT	bne	lb2	lda	#0	bra	lb3lb2	lda	ffAuxtypelb3	cmp	langNum	get the correct tab line	beq	lb4	sta	langNum	jsr	GetTabslb4	rtserr1	puts	#'Files must be source or text: ',errout=t	ph4	#fname	ph2	#1	jsr	PrintFileName	putcr errout=t	bra	err3err2	ph4	#fname	ph2	#1	jsr	PrintFileName	puts	#' could not be opened.',cr=t,errout=terr3	lda	#-1	brl	Quit	end******************************************************************  PrintFileName - write a file name to error out**  Inputs:*	fptr - file name pointer pointer*	errout - error out flag******************************************************************PrintFileName startlen	equ	1	length of the name	sub	(4:fptr,2:errout),2	ldy	#2	dereference the handle	lda	[fptr],Y	tax	lda	[fptr]	sta	fptr	stx	fptr+2	ora	fptr+2	beq	lb2	lda	[fptr]	get the length	beq	lb2	sta	len	add4	fptr,#2	print the characterslb1	lda	[fptr]	and	#$00FF	sta	ch	lda	errout	bne	lb1a	putc	ch	bra	lb1blb1a	putc	ch,errout=tlb1b	inc4	fptr	dec	len	bne	lb1lb2	retch	ds	2	temp character	end******************************************************************  ProDOSError - flag a ProDOS error**  Inputs:*	A - error number******************************************************************ProDOSError start	sta	er_num	OSError er_DCB	rtser_DCB	dc	i'1'er_num	ds	2	end******************************************************************  Purge - Purge a source file**  Inputs:*	fname - name of the file to purge******************************************************************Purge	start	using Common	using FileNames	using FileCommon	move4 fname,ffPathname	purge the file	lda	#7	sta	ffAction	lda	#$C000	sta	ffFlags	OSFastFile ffDCB	rts	end******************************************************************  Quit - quit**  Inputs:*	A - return code******************************************************************Quit	start	jsr	StopSpin	OSQuit qt_DCBqt_DCB	dc	i'2'	quit DCB	dc	a4'qt_flags'qt_flags dc	i'0'	end******************************************************************  WriteFile - Copy the macro file to the output file**  Inputs:*	oname - output file name*	chhand - handle of the macro file*	chdisp - size of file******************************************************************WriteFile start	using Common	using FileNames	using FileCommon	lda	chdisp	quit if the file is empty	ora	chdisp+2	bne	lb1	rtslb1	ph4	#oname	expand devices	jsr	ExpandDevice	tax	jne	err	la	ffAction,3	save the file	stz	ffIndex	la	ffFlags,$C000	move4 chhand,ffFilehandle	move4 oname,ffPathname	la	ffAccess,$C3	la	ffFiletype,TXT	lla	ffAuxtype,0	la	ffStorageType,1	lla	ffCreate,0	lla	ffCreate+4,0	lla	ffMod,0	lla	ffMod+4,0	lla	ffOption,0	move4 chdisp,ffFilelength	lla	ffBlocksUsed,0	OSFastFile ffDCB	bcs	err	la	ffAction,7	purge the file	la	ffFlags,$C000	move4 oname,ffPathname	OSFastFile ffDCB	bcs	err	rts;;  Allow another chance if an error occurs;err	pha		print error message	puts	#'Error writing to ',errout=t	ph4	#oname	ph2	#1	jsr	PrintFileName	puts	#' (',errout=t	pla	jsr	ProDOSError	puts	#').',cr=t,errout=t	puts	#'Output file name: '	print prompt	jsr	GetLine	get new file name	jsr	NextToken	strlen token	if not nul then	beq	err2	ph4	#token	  go try it	ph4	#oname	jsr	CopyFileNameerr2	rts		return	end